        public static void Validate()
        {
            if (DataA.Count != DataB.Count)
                throw new InvalidOperationException("A면 데이터와 B면 데이터의 행 개수는 반드시 같아야 합니다.");

            for (int i = 0; i < DataA.Count; i++)
            {
                if (DataA[i].Length != FrameSizePerSide)
                    throw new InvalidOperationException($"A면 데이터 {i}번째 행 길이가 47이 아닙니다. 현재 길이: {DataA[i].Length}");
            }

            for (int i = 0; i < DataB.Count; i++)
            {
                if (DataB[i].Length != FrameSizePerSide)
                    throw new InvalidOperationException($"B면 데이터 {i}번째 행 길이가 47이 아닙니다. 현재 길이: {DataB[i].Length}");
            }

            if (PositionData.Count == 0)
                throw new InvalidOperationException("position_data가 비어 있습니다.");
        }
    }
